if [ "$(sed -n "${L}p" mutated.c)" != "$LINE_TXT" ]; then echo "LINEMISS (line $L)"; exit 1; fi
M="$MUT_TXT" perl -i -pe "s/.*/\$ENV{M}/ if \$. == $L" mutated.c
